import { useRef } from 'react';


import { OverlayStackingProvider } from '../../../../../../core/providers/OverlayStackingProvider.js';
import { Tooltip } from '../../../../../../overlays/tooltip/Tooltip.js';
import { TruncationMode } from '../../../../../../typography/text-ellipsis/TextEllipsis.js';
import { DEFAULT_TRUNCATION_MODE } from '../../../../constants.js';
import { useTruncationDetector } from '../../../../hooks/useTruncationDetector.js';
import { TooltipItem } from '../../../../types/tooltip.js';
import { singleLineName } from '../../../../utils/single-line-name.js';
import { ChartTextEllipsis } from '../../../text-ellipsis/ChartTextEllipsis.js';
import {
  multipleDimensionItem,
  multipleDimensionContainer,
  singleDimensionContainer,
} from '../../shared/styles/SeriesBasedContent.sty.js';

export interface SeriesNameProps {
  names: string[];
  item: TooltipItem;
  nameFormatter?: (item: TooltipItem) => string;
  singleLine: boolean;
  highlighted: boolean;
  truncationMode?: TruncationMode;
  isScrolling?: boolean;
}

export const SeriesName = ({
  names,
  item,
  nameFormatter,
  singleLine,
  highlighted,
  truncationMode,
  isScrolling,
}: SeriesNameProps) => {
  const textRef = useRef<HTMLSpanElement>(null);
  const name = nameFormatter?.(item) ?? singleLineName(item.name);

  const isTruncated = useTruncationDetector(textRef, name);

  return (
    <OverlayStackingProvider>
      <Tooltip text={name} disabled={isScrolling || !isTruncated}>
        {singleLine ? (
          <div className={singleDimensionContainer({ highlighted })}>
            <ChartTextEllipsis
              ref={textRef}
              truncationMode={truncationMode ?? DEFAULT_TRUNCATION_MODE}
              aria-label="Series name"
            >
              {name}
            </ChartTextEllipsis>
          </div>
        ) : (
          <div className={multipleDimensionContainer({ highlighted })}>
            {names.map((dim, index) => (
              <span
                className={multipleDimensionItem}
                key={`dimension-${index}`}
              >
                <ChartTextEllipsis
                  truncationMode={truncationMode ?? DEFAULT_TRUNCATION_MODE}
                  aria-label="Series name"
                >
                  {dim}
                </ChartTextEllipsis>
              </span>
            ))}
          </div>
        )}
      </Tooltip>
    </OverlayStackingProvider>
  );
};

SeriesName['displayName'] = 'SeriesName';
